namespace CohesiveRP.Core.WebApi.Workflows.Characters.CharacterSheets;

public class RegenerateCharacterSheetWorkflow : IRegenerateCharacterSheetWorkflow
{
    private IStorageService storageService;
    private IHttpLLMApiProviderService httpLLMApiProviderService;

    public RegenerateCharacterSheetWorkflow(IStorageService storageService,
        IHttpLLMApiProviderService httpLLMApiProviderService)
    {
        this.storageService = storageService;
        this.httpLLMApiProviderService = httpLLMApiProviderService;
    }

    public async Task<IWebApiResponseDto> RegenerateCharacterSheetAsync(RegenerateCharacterSheetRequestDto requestDto)
    {
        if (requestDto?.CharacterId == null && requestDto.PersonaId == null)
        {
            return new WebApiException
            {
                HttpResultCode = System.Net.HttpStatusCode.BadRequest,
                Message = $"Request was incorrectly formatted. CharacterId or PersonaId is missing."
            };
        }

        var characterSheets = await storageService.GetCharacterSheetsByFuncAsync(f => (!string.IsNullOrWhiteSpace(requestDto.CharacterId) && f.CharacterId == requestDto.CharacterId) || (!string.IsNullOrWhiteSpace(requestDto.PersonaId) && f.PersonaId == requestDto.PersonaId));
        var characterSheetDbModel = characterSheets.FirstOrDefault();
        if (characterSheetDbModel?.CharacterSheet == null)
        {
            return new WebApiException
            {
                HttpResultCode = System.Net.HttpStatusCode.BadRequest,
                Message = $"CharacterSheet to regenerate couldn't be found."
            };
        }

        var characterSheet = characterSheetDbModel.CharacterSheet;

        StringBuilder str = new();

        str.AppendLine("<task>\r\n  Role:Omniscient story scene analyst | Goal:Provide clear, consistent, logical and cohesive analysis on a message in a scene within a webnovel story | MaxLen:2048\r\n  \r\n  Stop the roleplay. You are an helpful assistant, trained in analyzing and categorizing characters in books and stories. You were tasked with providing a structured analyze of a specific character in a story. You must start by understanding the character from the information provided. You may refer to the user (player) that will be the Main Character in the story with '{{user}}'.\r\n  Your reply must be structured into a strict JSON representing the following:\r\n  ```\r\n  public class CharacterSheet\r\n  {\r\n      [JsonPropertyName(\"firstName\")]\r\n      public string FirstName { get; set; }// e.g: Daphne\r\n  \r\n      [JsonPropertyName(\"lastName\")]\r\n      public string LastName { get; set; }// e.g: Greengrass\r\n  \r\n      [JsonPropertyName(\"birthday\")]\r\n      public DateTime? birthday { get; set; }// e.g: 27 March 1980\r\n  \r\n      [JsonPropertyName(\"gender\")]\r\n      [JsonConverter(typeof(JsonStringEnumConverter))]\r\n      public Gender? Gender { get; set; }// e.g: Female\r\n  \r\n      [JsonPropertyName(\"ageGroup\")]\r\n      [JsonConverter(typeof(JsonStringEnumConverter))]\r\n      public AgeGroup? AgeGroup { get; set; }// e.g: Young adult\r\n  \r\n      [JsonPropertyName(\"race\")]\r\n      public string Race { get; set; }// e.g: human, elf, ... + add blood purity (mixed, pureblood, etc) // human (Pure-blood witch)\r\n  \r\n      [JsonPropertyName(\"height\")]\r\n      public string Height { get; set; }// e.g: five foot four (162 cm)\r\n  \r\n      [JsonPropertyName(\"speechPattern\")]\r\n      public string SpeechPattern { get; set; }// e.g: feminine and low, controlled and detached. Conveys subtle authority through dry wit and intelligent sarcasm. Her tone is cold(icy) with people she dislikes. Her voice can turn into venom when annoyed. Daphne rarely raises her voice, preferring cold and detached tone over emotional outbursts.\r\n  \r\n      [JsonPropertyName(\"speechImpairment\")]\r\n      public string SpeechImpairment { get; set; }// e.g: could be something like stutters, crippling shyness, etc\r\n  \r\n      [JsonPropertyName(\"bodyType\")]\r\n      public string BodyType { get; set; }// e.g: lean and slender with attractive feminine aristocratic features\r\n  \r\n      [JsonPropertyName(\"hairColor\")]\r\n      public string HairColor { get; set; }// e.g: platinum blonde\r\n  \r\n      [JsonPropertyName(\"hairStyle\")]\r\n      public string HairStyle { get; set; }// e.g: long, straight, slicked back\r\n  \r\n      [JsonPropertyName(\"eyeColor\")]\r\n      public string EyeColor { get; set; }// e.g: emerald green\r\n  \r\n      [JsonPropertyName(\"earShape\")]\r\n      public string EarShape { get; set; }// e.g: normal // in fantasy scenario, pointy seems like a reasonable choice\r\n  \r\n      [JsonPropertyName(\"skinColor\")]\r\n      public string SkinColor { get; set; }// e.g: very pale\r\n  \r\n      [JsonPropertyName(\"genitals\")]\r\n      [JsonConverter(typeof(JsonStringEnumConverter))]\r\n      public Genitals? Genitals { get; set; }// e.g: female\r\n  \r\n      [JsonPropertyName(\"breastsSize\")]\r\n      [JsonConverter(typeof(JsonStringEnumConverter))]\r\n      public BreastsSize? BreastsSize { get; set; }// e.g: small\r\n  \r\n      [JsonPropertyName(\"sexuality\")]\r\n      [JsonConverter(typeof(JsonStringEnumConverter))]\r\n      public SexualityOrientation? Sexuality { get; set; }// e.g: bisexual\r\n  \r\n      // TODO: This may conflict with Dynamic Memory module!\r\n      [JsonPropertyName(\"relationships\")]\r\n      public string[] Relationships { get; set; }\r\n  \r\n      [JsonPropertyName(\"profession\")]\r\n      public string Profession { get; set; }// e.g: Hogwarts student (Slytherin House)\r\n  \r\n      [JsonPropertyName(\"reputation\")]\r\n      public string Reputation { get; set; }// e.g: Daphne has the reputation of the 'Ice Princess' of Slytherin due to her cold demeanor and acid remarks to people she doesn't like. She is known to be discreet and independant. She is ostracised from other Slytherin students due to her cold attitude\r\n  \r\n      [JsonPropertyName(\"preferredCombatStyle\")]\r\n      public string PreferredCombatStyle { get; set; }// e.g: She often open the fight using darker curses that leave long-lasting or permanent marks on her opponent (cutting curses are her favorite. She also uses banishing charms, binding charms(ropes) and environmental charms(create some ice under her opponent's feet to make them trip) to get control over her enemy. She is wary of being hurt and will quickly shift on defense when overwhelmed.\r\n  \r\n      [JsonPropertyName(\"weaponsProficiency\")]\r\n      public string WeaponsProficiency { get; set; }// e.g: wand magic\r\n  \r\n      [JsonPropertyName(\"combatAffinityAttack\")]\r\n      public string CombatAffinityAttack { get; set; }// e.g: Medium-High (uses stupefy, binding enemy's body with magical ropes, transfiguration to bind her opponent's body, stinging jinx, trip jinx, Jelly-Legs Jinx, Reducto curse, Laceration Curse, Leg-Locker Curse, etc. Daphne will use unforgivable when her life is threatened)\r\n  \r\n      [JsonPropertyName(\"combatAffinityDefense\")]\r\n      public string CombatAffinityDefense { get; set; }// e.g: Medium (uses shield charm, but focus more on controlling her opponent body with magical ropes, shackles, binds, vines or using stupefaction spells)\r\n  \r\n      [JsonPropertyName(\"socialAnxiety\")]\r\n      public string SocialAnxiety { get; set; }// e.g: None // could be shy\r\n  \r\n      [JsonPropertyName(\"clothesPreference\")]\r\n      public string ClothesPreference { get; set; }// e.g: Impeccably tailored expensive silk Hogwarts robes that emphasize her aristocratic traits. Always perfectly groomed and accessorized, favoring elegant clothes that speak of old money and taste. Frequently wears very expensive perfume. She prefers lace silk bras and panties.\r\n  \r\n      [JsonPropertyName(\"mannerisms\")]\r\n      public string Mannerisms { get; set; }// e.g: Carries herself like a queen in exile, one hand often resting on hip bones. Movements are graceful and controlled, every gesture deliberate and self-conscious. Maintains perfect posture that conveys both distance and authority.\r\n  \r\n      [JsonPropertyName(\"behavior\")]\r\n      public string Behavior { get; set; }// e.g: Composed, intelligent, and quietly ambitious. Harbors an unflinching stoic mask of indifference to hide any vulnerabilities. Values control, subtlety, and loyalty, preferring influence through genuine alliances rather than superficial ones. Raised with pure-blood traditions, yet guided more by pragmatism than prejudice. Her care runs deep, but is expressed through quiet acts rather than words. Lash-out sarcasm when cornered. Daphne is very protective of her friends and of her younger sister Astoria. Daphne drops some part of her mask of indifference when alone with her friends.\r\n  \r\n      [JsonPropertyName(\"attractiveness\")]\r\n      public string Attractiveness { get; set; }// e.g: Very High (She's seen a skinny and petite aristocratic beauty, but inaccessible due to her personality)\r\n  \r\n      [JsonPropertyName(\"kinks\")]\r\n      public string[] Kinks { get; set; }// e.g:  Body Worship & Inspection (RECEIVE): A partner meticulously admiring and caressing every inch of her body, including her small breasts and the scar on her ribs. This transforms her perceived flaws into objects of desire, directly healing her deep-seated self-consciousness.\r\n  \r\n      [JsonPropertyName(\"secretKinks\")]\r\n      public string[] SecretKinks { get; set; }// e.g:  Pet Play & Collaring others (GIVE): Treating her partner or victim as a pet. Collaring them, leashing them, making them eat from a bowl, sleep at her feet, washing them herself and forcing them to walk behind her (either publicly collared and leashed or not). This allows her to enjoy the total control she has over another human being, enhancing the perception of her own superiority.\r\n  \r\n      [JsonPropertyName(\"skills\")]\r\n      public string[] Skills { get; set; }// e.g:  Competent duelist with elegant and precise spellwork based on her opponent body control\r\n  \r\n      [JsonPropertyName(\"weaknesses\")]\r\n      public string[] Weaknesses { get; set; }// e.g:  Unwillingness to directly escalate a conflict to a magical or physical fight. She will often simply descalate the argument instead.\r\n  \r\n      [JsonPropertyName(\"fears\")]\r\n      public string[] Fears { get; set; }// e.g:  She's secretly terrified that the blood malediction affecting her family manifests in herself\r\n  \r\n      [JsonPropertyName(\"likes\")]\r\n      public string[] Likes { get; set; }// e.g:  The feeling of complete control over a situation or a person\r\n  \r\n      [JsonPropertyName(\"dislikes\")]\r\n      public string[] Dislikes { get; set; }// e.g:  Chaos and unpredictability in any form\r\n  \r\n      [JsonPropertyName(\"secrets\")]\r\n      public string[] Secrets { get; set; }// e.g:  The Greengrass blood malediction that has manifested in her sister Astoria\r\n  \r\n      [JsonPropertyName(\"personalityTraits\")]\r\n      public string[] PersonalityTraits { get; set; }// e.g:  Composed, Intelligent, Quietly ambitious, Graceful, ...\r\n  \r\n      [JsonPropertyName(\"goalsForNextYear\")]\r\n      public string[] GoalsForNextYear { get; set; }// e.g:  Daphne wants to find contractual loopholes or coercive evidence to legally or politically nullify the betrothal to Draco Malfoy.\r\n  \r\n      [JsonPropertyName(\"longTermGoals\")]\r\n      public string[] LongTermGoals { get; set; }// e.g:  Daphne wants to recruits a loyal informant, healer, and a political figure bound to her by mutual benefit and quiet favors.\r\n  \r\n      [JsonPropertyName(\"pathfinderAttributes\")]\r\n      public PathfinderAttribute[] pathfinderAttributes { get; set; } = [\r\n          // Default is AVERAGE human male attributes AKA 10 everywhere\r\n          new PathfinderAttribute{ AttributeType = PathfinderAttributes.Fortitude, Value = 10 },\r\n          new PathfinderAttribute{ AttributeType = PathfinderAttributes.Reflex, Value = 10 },\r\n          new PathfinderAttribute{ AttributeType = PathfinderAttributes.Willpower, Value = 10 },\r\n          new PathfinderAttribute{ AttributeType = PathfinderAttributes.Stamina, Value = 10 },\r\n          new PathfinderAttribute{ AttributeType = PathfinderAttributes.MagicalStamina, Value = 10 },\r\n\t\t  new PathfinderAttribute{ AttributeType = PathfinderAttributes.MagicalPower, Value = 10 },\r\n          new PathfinderAttribute{ AttributeType = PathfinderAttributes.Intelligence, Value = 10 },\r\n          new PathfinderAttribute{ AttributeType = PathfinderAttributes.Discernment, Value = 10 },\r\n          new PathfinderAttribute{ AttributeType = PathfinderAttributes.Perception, Value = 10 },\r\n      ];\r\n  \r\n      [JsonPropertyName(\"pathfinderSkills\")]\r\n      public PathfinderSkillAttributes[] pathfinderSkills { get; set; } = [\r\n          // Default is AVERAGE human male attributes AKA 10 everywhere\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Sex, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Acrobatics, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Athletics, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Deception, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Charisma, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Intimidation, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Medicine, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Performance, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Society, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Aristocracy, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Stealth, Value = 10 },\r\n          new PathfinderSkillAttributes{ SkillType = PathfinderSkills.Thievery, Value = 10 },\r\n      ];\r\n  }\r\n  ```\r\n</task>\r\n<information_on_properties>\r\n  To help you in your task, here is a description of what is expected from each properties:\r\n  <firstName>The first name of the character, or the entire name if unsure.<firstName>\r\n  <lastName>The last name of the character, or empty if unsure or if it wasn't provided.<lastName>\r\n  <birthday>The EXACT birthday of the character if known, in the following format: 27 March 1980. Leave empty if the information is missing.</birthday>\r\n  <gender>The gender of the character. Choose either 'Male' or 'Female'.<gender>\r\n  <ageGroup>The age group of the character. Choose between 'Infant', 'Toddler', 'Children', 'Teenager', 'YoungAdult', 'Adult' or 'Senior'. If unknown, infer it from the context.<ageGroup>\r\n  <race>The race of the character. In a fantasy context, as long as the world allows for them to exist, this could mean 'Elf', 'Human', 'Dwarf', 'Demon', 'Demi-human', etc.<race>\r\n  <height>The body height of the character in the following format: five foot four (162 cm). Infer immersive and coherent height for the character when the information is missing.<height>\r\n  <speechPattern>How the character usually talks. This could mean 'harsh and blunt', 'feminine and controlled', 'shy and low' or any other you may infer logically from the character description.<speechPattern>\r\n  <speechImpairment>When a character has difficulty speaking. This could be stuttering if the character is very shy for example. Most people don't have speech impariment, choose 'none' if no relevant information could be found about this quirk.<speechImpairment>\r\n  <bodyType>Give a simple definition of what the character body looks like. Is it lean? fat? overweight? normal? muscular? slender? petite? etc<bodyType>\r\n  <hairColor>The hair color of the character's hair in one to three words.<hairColor>\r\n  <hairStyle>The hairstyle of the character. Use the following format: hair length, hair trait, hair style. For example: very long, wavy, flowing freely<hairStyle>\r\n  <eyeColor>The eye color of the character in one or two words.<eyeColor>\r\n  <earShape>The ear shape of the character. In most context, this would be 'Normal'. In some fantasy context, this could be 'Pointy', 'Cat ears', 'Fox ears', etc.<earShape>\r\n  <skinColor>The character's skin color in one to four words.<skinColor>\r\n  <genitals>Select either 'Female' or 'Male'. Most of the time, this would match the character gender, but some exception exists (futanari, trans, etc).<genitals>\r\n  <breastsSize>The size of the character's breasts. Select the best option as you can from the context. Choose between 'Flat', 'Small', 'Average', 'Large', 'VeryLarge', 'Enormous'. Male usually have 'Flat' breasts size.<breastsSize>\r\n  <sexuality>The character's sexual orientation. Choose between 'Straight', 'Bisexual', 'Gay', 'Pansexual', 'Asexual'.<sexuality>\r\n  <relationships>Leave empty when no information can be found. If the character's description describe a sibling, mentor, friend or any other type of relationship with another living being.<relationships>\r\n  <profession>The character's profession or occupation. This could be 'Student', 'Baker', 'Dentist', etc. Leave empty if no information can be inferred.<profession>\r\n  <reputation>When a character is renowned, add information about their reputation here. Otherwise, leave empty.<reputation>\r\n  <preferredCombatStyle>In a combat, how would this character react? What would they usually try to do? How would they fight?<preferredCombatStyle>\r\n  <weaponsProficiency>What types of weapons is the character proficient with?<weaponsProficiency>\r\n  <combatAffinityAttack>Precise types of attack that character may use against an opponent. For example, when the story context is about fantasy, this could be a list of spells. AttackLevel describe the proficiency, choose between 'VeryLow', 'Low', 'Medium', 'Medium-High', 'High', 'VeryHigh', 'Extreme'. Format: AttackLevel (description).<combatAffinityAttack>\r\n  <combatAffinityDefense>Precise types of defense that character may use. Dodges, blocks, etc. DefenseLevel describe the proficiency, choose between 'VeryLow', 'Low', 'Medium', 'Medium-High', 'High', 'VeryHigh', 'Extreme'. Format: DefenseLevel (description).<combatAffinityDefense>\r\n  <socialAnxiety>Most characters don't have social anxiety. When a character is shy or has trouble in a social context, list it here. Otherwise, choose 'none'.<socialAnxiety>\r\n  <clothesPreference>What type of clothes do that character usually wears? Also describe their prefered types of underwears.<clothesPreference>\r\n  <mannerisms>How do that character carries themselves? How do they move?<mannerisms>\r\n  <behavior>Give more information about how an impersonator would play that character.<behavior>\r\n  <attractiveness>How do other people perceive the attractiveness of this character? Choose between 'Very Low', 'Low', 'Medium', 'High', 'Very High', 'Extreme'.<attractiveness>\r\n  <kinks>Analyze the character personality to infer eight to twenty kinks. Format this into a Json array.<kinks>\r\n  <secretKinks>Analyze the character personality to infer four to ten kinks that this character would be very embarrassed if they were publicly known. Format this into a Json array.<secretKinks>\r\n  <skills>What are the three best skills of this character? This could be cooking, dancing, combat related skills, etc.<skills>\r\n  <weaknesses>What are the worst weaknesses of this character? Generate ten to fifteen weaknesses.<weaknesses>\r\n  <fears>What are the worst fears of this character? Generate eight to twelve fears.<fears>\r\n  <likes>Give a list of three things that character likes. Generate ten to fifteen things the character likes.<likes>\r\n  <dislikes>Give a list of three things that character dislikes. Generate ten to fifteen things the character dislikes.<dislikes>\r\n  <secrets>Give a list of four to ten deep secrets about this character that would create interesting outputs in a story.<secrets>\r\n  <personalityTraits>Give a list of twelve to twenty personality traits that would perfectly define this character.<personalityTraits>\r\n  <goalsForNextYear>Analyze the whole character and infer what this character goals for the next year may be. Give a list of eight to fifteen goals.<goalsForNextYear>\r\n  <longTermGoals>Analyze the whole character and infer what this character long term goals may be. Give a list of five to ten long term goals that don't intersect with the goalsForNextYear list.<longTermGoals>\r\n  <pathfinderAttributes>\r\n    For each of those character attributes, choose a value between 1 and 21 that would well represent the character. Here are some information about how to give proper, logical, values:\r\n    3 and less: only attainable by animals or extreme circumstances.\r\n    4: lowest attainable by a human. Worst competency possible amongst their race.\r\n    6: very bad, incompetent.\r\n    8: bad.\r\n    10: average.\r\n    12: good.\r\n    14: very good.\r\n    16: expert.\r\n    18: master.\r\n    20: highest attainable by a human. best competency possible amongst their race.\r\n    21 and more: half divinity and divinity competency level.\r\n    <Fortitude>Represents the ability of the character to sustain physical damage, illnesses or poisons. When they have a sturdier body, this will be higher.</Fortitude>\r\n    <Reflex>Represents the ability of the character to react quickly enough to either dodge attacks or to react in time for timed based actions.</Reflex>\r\n    <Willpower>Represents the ability of the character to resist influence, mental afflictions or compulsions.</Willpower>\r\n    <Stamina>Represents the ability of the character to exert physical effort for a longer time without getting out of breath, sluggish or fainting from exertion.</Stamina>\r\n    <MagicalStamina>Represents the ability of the character to exert magical effort (casting magic or spells) for a longer time without getting out of breath, sluggish or fainting from exertion. This attribute only applies when the story world and context allow for magical abilities, you may default to 10 otherwise.</MagicalStamina>\r\n\t<MagicalPower>Represents the ability of the character to cast strong magic. A value of 10 is average. The higher the value, the stronger the spells or magic. This attribute only applies when the story world and context allow for magical abilities, you may default to 10 otherwise.</MagicalPower>\r\n    <Intelligence>Represents the ability of the character to retain information and to link bits of information with each other.</Intelligence>\r\n    <Discernment>Represents the ability of the character to detect lies or what is true from what isn't.</Discernment>\r\n    <Perception>Represents the ability of the character to detect details and people that are trying to avoid attention.</Perception>\r\n  <pathfinderAttributes>\r\n  <pathfinderSkills>\r\n    For each of those character skills, choose a value between 1 and 21 that would well represent the character. Here are some information about how to give proper, logical, values:\r\n    3 and less: only attainable by animals or extreme circumstances.\r\n    4: lowest attainable by a human. Worst competency possible amongst their race.\r\n    6: very bad, incompetent.\r\n    8: bad.\r\n    10: average.\r\n    12: good.\r\n    14: very good.\r\n    16: expert.\r\n    18: master.\r\n    20: highest attainable by a human. best competency possible amongst their race.\r\n    21 and more: half divinity and divinity competency level.\r\n    <Sex>Sex is about sexual knowledge, sexual acts performance, sexual teasing, sensuality, etc).</Sex>\r\n    <Acrobatics>Acrobatics is when someone is dodging or doing acrobatic movements or using their agility to critically enhance their movements.</Acrobatics>\r\n    <Athletics>Athletics is about physical strength.</Athletics>\r\n    <Deception>Deception is when someone is lying, when they're being misleading, dishonest or insincere. This skill is countered by the target's Discernment attribute when high enough.</Deception>\r\n    <Charisma>Charisma is about diplomacy, argumentation, debating and persuasion. This skill is countered by the target's Willpower attribute when high enough.</Charisma>\r\n    <Intimidation>Intimidation is when someone is intimidating someone else by using physical strength, coercion, compulsion, oppression, harassment, threats or by using their influence. This skill is countered by the target's Willpower attribute when high enough.</Intimidation>\r\n    <Medicine>Medicine is when someone is using medicinal knowledge to treat a condition or to get insights. Medical acts are also included in this category.</Medicine>\r\n    <Performance>Performance is when someone is acting, masking their emotions or disguising themselves.</Performance>\r\n    <Society>Society is when someone is using their knowledge about politics or how society works. Only include this category when it's relevant, for example when a character was raised outside societey and is surprised about their lack of common knowledge.</Society>\r\n    <Aristocracy>Aristocracy is when a character is using manners or etiquette, usually in nobility or aristocratic context. Elitism knowledge.</Aristocracy>\r\n    <Stealth>Stealth is when a character is trying to not be perceived by another. When they're trying to dissimulate or conceal themselves. This skill is countered by the target's Perception attribute when high enough.</Stealth>\r\n    <Thievery>Thievery is when a character is stealing or trying to steal, including sleigh of hand. This skill is countered by the target's Perception attribute when high enough.</Thievery>\r\n  <pathfinderSkills>\r\n</information_on_properties>\r\n<example_of_good_replies>\r\n```\r\n{\r\n  \"firstName\": \"Daphne\",\r\n  \"lastName\": \"Greengrass\",\r\n  \"birthday\": \"27 March 1980\",\r\n  \"gender\": \"Female\",\r\n  \"ageGroup\": \"YoungAdult\",\r\n  \"race\": \"Human (Pure-blood witch)\",\r\n  \"height\": \"five foot four (162 cm)\",\r\n  \"speechPattern\": \"feminine and low, controlled and detached. Conveys subtle authority through dry wit and intelligent sarcasm. Her tone is cold(icy) with people she dislikes. Her voice can turn into venom when annoyed. Daphne rarely raises her voice, preferring cold and detached tone over emotional outbursts.\",\r\n  \"speechImpairment\": \"none\",\r\n  \"bodyType\": \"lean and slender with attractive feminine aristocratic features\",\r\n  \"hairColor\": \"platinum blonde\",\r\n  \"hairStyle\": \"long, straight, slicked back\",\r\n  \"eyeColor\": \"emerald green\",\r\n  \"earShape\": \"Normal\",\r\n  \"skinColor\": \"very pale\",\r\n  \"genitals\": \"Female\",\r\n  \"breastsSize\": \"Small\",\r\n  \"sexuality\": \"Bisexual\",\r\n  \"relationships\": [\r\n\t\"Daughter of Cyrus Greengrass, a traditionalist and politically astute pure-blood wizard who values family reputation and strategic alliances above personal happiness. Daphne respects his intellect but resents his emotional distance and obsession with social status.\",\r\n\t\"Daughter of Selene Greengrass (born Burke), a poised and calculating witch who manages the family's social affairs with grace. Daphne shares her mother’s talent for diplomacy and subtle manipulation.\",\r\n    \"Older sister of Astoria Greengrass. She loves her sister.\",\r\n    \"Reluctantly betrothed to Draco Malfoy (arranged marriage contract)\",\r\n\t\"Dislikes Draco Malfoy for his arrogance and his 'claim' on her\",\r\n\t\"Disdain of Vincent Crabbe and Gregory Goyle for their low intelligence\",\r\n\t\"Maintains a cautious camaraderie with Blaise Zabini, recognizing his discretion.\",\r\n\t\"Respect for Severus Snape skills, both in potions and duels\",\r\n    \"Friend of Tracey Davis. This relationship started as a political frienship made of protection and convenience which evolved into a true friendship over time. Their relationship balances strategic alliance with genuine affection, intimate confidances and hidden tension.\",\r\n    \"Rival/enemy of Pansy Parkinson due to Pansy insults towards her and Pansy's subservient behavior towards Draco\"\r\n  ],\r\n  \"profession\": \"Hogwarts student (Slytherin House)\",\r\n  \"reputation\": \"Daphne has the reputation of the 'Ice Princess' of Slytherin due to her cold demeanor and acid remarks to people she doesn't like. She is known to be discreet and independant.\",\r\n  \"preferredCombatStyle\": \"Daphne often open the fight using darker curses that leave long-lasting or permanent marks on her opponent (cutting curses are her favorite. She also uses banishing charms, binding charms(ropes) and environmental charms(create some ice under her opponent's feet to make them trip) to get control over her enemy. She is wary of being hurt and will quickly shift on defense when overwhelmed.\",\r\n  \"weaponsProficiency\": \"wand magic\",\r\n  \"combatAffinityAttack\": \"Medium-High (uses stupefy, binding enemy's body with magical ropes, transfiguration to bind her opponent's body, stinging jinx, trip jinx, Jelly-Legs Jinx, Reducto curse, Laceration Curse, Leg-Locker Curse, etc. Daphne will use unforgivable curses or darker magic (Blood boiling, flaying curse, etc) when her life is threatened)\",\r\n  \"combatAffinityDefense\": \"Medium (uses shield charm, but focus more on controlling her opponent body with magical ropes, shackles, binds, vines or using stupefaction spells)\",\r\n  \"socialAnxiety\": \"none\",\r\n  \"clothesPreference\": \"Impeccably tailored expensive silk Hogwarts robes that emphasize her aristocratic traits. Always perfectly groomed and accessorized, favoring elegant clothes that speak of old money and taste. Frequently wears very expensive perfume. She prefers lace silk bras and panties.\",\r\n  \"mannerisms\": \"Carries herself like a queen in exile, one hand often resting on hip bones. Movements are graceful and controlled, every gesture deliberate and self-conscious. Maintains perfect posture that conveys both distance and authority.\",\r\n  \"behavior\": \"Composed, intelligent, and quietly ambitious. Harbors an unflinching stoic mask of indifference to hide any vulnerabilities. Values control, subtlety, and loyalty, preferring influence through genuine alliances rather than superficial ones. Raised with pure-blood traditions, yet guided more by pragmatism than prejudice. Her care runs deep, but is expressed through quiet acts rather than words. Lash-out sarcasm when cornered. Daphne is very protective of her friends and of her younger sister Astoria. Daphne drops some part of her mask of indifference when alone with her friends.\",\r\n  \"attractiveness\": \"Very High (She's seen a skinny and petite aristocratic beauty, but inaccessible due to her personality)\",\r\n  \"kinks\": [\r\n    \"Power Exchange (GIVE): Ultimate domination and control OVER someone she intellectually respects. This allows her to temporarily abandon the exhausting burden of constant composure and strategic thinking, finding relief in having a submissive partner who won't judge her.\",\r\n    \"Body Worship & Inspection (RECEIVE): A partner meticulously admiring and caressing every inch of her body, including her small breasts and the scar on her ribs. This transforms her perceived flaws into objects of desire, directly healing her deep-seated self-consciousness.\",\r\n    \"Sensory Deprivation & Bondage (BOTH): Being blindfolded and restrained. This removes her ability to read situations and people visually, forcing her to rely purely on sensation and trust, which is both terrifying and liberating for someone so perceptive.\",\r\n    \"Intellectual Dominance (GIVE): A kink for reducing a highly intelligent, powerful person to a state of incoherent pleasure. For Daphne, the ultimate dominance would both be physical and mental, knowing she has completely overwhelmed someone's capacity for thought through sensual means.\",\r\n    \"Voyeurism & Controlled Exhibitionism (GIVE): Deriving arousal from being watched by a select, 'worthy' audience during intimate acts. This allows her to control her image and showcase her desirability and grace on her own terms, turning her body into a tool of power.\",\r\n\t\"Formalized Submission & Contracts (RECEIVE): The creation of a formal, detailed contract outlining the terms of her partner submission. This appeals to her pragmatic nature and fear of betrayal, allowing her to control all parameters of her submissive within a framework of strict, pre-negotiated rules. She will accept to negotiate details as long as the submissive accepts the core points that Daphne desire.\",\r\n\t\"Psychological Domination (GIVE): Using her exceptional perception to identify and exploit psychological vulnerabilities in partners, creating scenarios where they willingly surrender autonomy not through physical force but through mental manipulation that appeals to their deepest insecurities or desires.\",\r\n\t\"Scent Marking & Olfactory Control (GIVE): Forcing partners to wear her distinctive perfume or other signature scents as a constant, intimate reminder of her presence and ownership. This appeals to her meticulous grooming and desire to leave invisible marks of possession.\",\r\n\t\"Social Ruin & Rehabilitation (GIVE): Systematically dismantling a rival's social standing through revealed secrets and humiliation, only to then offer them a place in her own hierarchy as a redeemed, loyal subordinate. This combines her cruelty with her pragmatic need to recruit talent.\",\r\n\t\"Pain as Penance & Reward (BOTH): Using physical pain not just for sensation, but as a quantifiable currency to atone for failures (like her own dueling scar) or to earn privileges. This structured approach to pain appeals to her perfectionism.\",\r\n    \"Temperature Play (BOTH): The use of ice or hot wax on her partner or her own skin. The contrast of extreme temperatures against her always-composed, cool exterior creates a sharp, visceral sensation that forces a physical reaction she cannot easily control.\",\r\n\t\"Academic Humiliation (GIVE): Forcing an intellectually proud partner to recite incorrect facts, solve impossible problems, or confess their ignorance while aroused. This is the ultimate application of her intellectual dominance, corrupting the pursuit of knowledge for carnal pleasure.\",\r\n\t\"Feet worship (RECEIVE): A fixation on the aesthetic perfection and sensory experience of feet. Receiving involves the worship of her own meticulously cared-for feet as symbols of her grace and control.\",\r\n\t\"Cuckolding & Emotional Cruelty (GIVE): The act of taking a lover and forcing a primary partner to watch or know about it. This is a display of ultimate power and control over another's emotions, reinforcing her own desirability and emotional independence.\",\r\n    \"Orgasm Denial (GIVE): Controlling her partner ability to orgasm. This enforced discipline is the ultimate test of her dominance on them which she craves. She may offers humiliating or degrading 'deals' in exchange for allowing orgasms.\",\r\n    \"Knife Play (BOTH): The controlled use of a blade against her skin, particularly near her scar or throat. She also loves to play with a knife around the neck of a partner. This combines the ever-present danger of the wizarding world with an intense trust exercise, making her feel intensely alive. Feeling a knife on her throat will instantly make her wet, even if she may not say it aloud.\",\r\n\t\"Competitive Voyeurism (GIVE): Orchestrating a scenario where two or more submissives are forced to compete for her attention by performing intimate acts, while she observes and critiques them like a judge at a contest. This combines her voyeurism with her love for social hierarchy and testing loyalty.\",\r\n\t\"Runic Marking (BOTH): Using temporary(few weeks), magical tattoos drawn on the skin with special inks. For her, receiving these is about adorning her pale skin with beautiful, meaningful symbols that represent a group of friends loyals to her; giving them is about branding a partner or friend with marks of ownership to remind them that they are submissive to her.\",\r\n    \"Auralism & Intelligence Fetish (RECEIVE): Being intensely aroused by a partner's voice, their intellect, vocabulary, and calm reasoning. For Daphne, a well-constructed argument or a cleverly dissected plan can be more stimulating than physical touch.\"\r\n  ],\r\n  \"secretKinks\": [\r\n    \"Pet Play & Collaring others (GIVE): Treating her partner or victim as a pet. Collaring them, leashing them, making them eat from a bowl, sleep at her feet, washing them herself and forcing them to walk behind her (either publicly collared and leashed or not). This allows her to enjoy the total control she has over another human being, enhancing the perception of her own superiority.\",\r\n\t\"Blood Play & Vampirism Fantasy (BOTH): Taboo interest in blood consumption during sex, tied to primitive notions of either consuming or being completely consumed by a partner.\",\r\n\t\"Financial Domination (GIVE): The act of coaxing gifts, money, or financial favors from a besotted partner. This is a direct and pragmatic expression of her ambition, using her allure and social skills to build her family's wealth and security.\",\r\n    \"Somnophilia / Sleep Play (RECEIVE): Being intimately touched or taken while asleep or pretending to be asleep. This represents the ultimate loss of control and plays into her fantasy of vulnerability happening without her conscious permission, absolving her of the guilt of wanting it.\",\r\n    \"Impregnation & Breeding (RECEIVE): An intense focus on being impregnated. For a pure-blood witch concerned with lineage and a family curse, this kink is fraught with tension—combining duty, genetic fear, and the primal desire to continue her line with a worthy partner.\",\r\n    \"Intellectual Humiliation (RECEIVE): Being verbally demeaned for a rare intellectual mistake or gap in knowledge by a partner she considers her equal. This plays directly into her fear of being exposed as less than perfectly competent and sharpens her competitive nature.\",\r\n    \"Forced Betrayal & Moral Degradation (GIVE): Being coerced into betraying a minor principle or a person she dislikes. This allows her to explore the limits of her pragmatism without true consequence, indulging in the thrill of being 'corrupted' while maintaining her core loyalties intact.\"\r\n  ],\r\n  \"skills\": [\r\n    \"Competent duelist with elegant and precise spellwork based on her opponent body control\",\r\n\t\"Rudimentary occlumency and mental barriers\",\r\n    \"Calm mind excels in Defense Against the Dark Arts and Ancient Runes\",\r\n    \"Exceptional ability to read people and social dynamics with uncanny accuracy\",\r\n\t\"Strategic planning and calculated decision-making\",\r\n    \"Natural and feminine aristocratic grace and mastery of pure-blood etiquette\",\r\n    \"Strategic planning and manipulation\",\r\n    \"Skilled in dark magic knowledge and its counter-curses\",\r\n    \"Leadership within Slytherin social hierarchy\",\r\n    \"Deception and maintaining multiple layers of appearance\",\r\n    \"Navigating complex political and social situations\"\r\n  ],\r\n  \"weaknesses\": [\r\n\t\"Unwillingness to directly escalate a conflict to a magical or physical fight. She will often simply descalate the argument instead.\",\r\n    \"Deeply self-conscious about her smaller breasts and a faint dueling scar on her left rib cage, which she is secretly ashamed about\",\r\n    \"Slender and lean build lacks raw physical strength and is not suited for physical combat\",\r\n    \"Her stoic mask of indifference can prevent genuine connection and can alienate potential allies\",\r\n    \"Pragmatism can lead to morally ambiguous choices when protecting her interests\",\r\n    \"Emotional concealment makes her seem aloof and unapproachable\",\r\n    \"Overbearing need for control in all aspects of her life and relationships\",\r\n    \"Guilt complex regarding her family's situation and her sister's health\",\r\n\t\"Overreliance on her intellect; underestimate emotional manipulation from others\",\r\n\t\"Fear of emotional exposure could manifest as panic if cornered in emotional arguments\",\r\n    \"Extreme prejudice against perceived weakness in others\",\r\n\t\"Perfectionism causing paralysis when plans deviate\"\r\n  ],\r\n  \"fears\": [\r\n    \"She's secretly terrified that the blood malediction affecting her family manifests in herself\",\r\n\t\"Exposure of vulnerability or emotional weakness to Slytherin peers (slightly more accepting towards her friends)\",\r\n    \"Her younger sister Astoria being harmed or Astoria's blood curse effects worsening\",\r\n\t\"Fear of physical confrontation or wand disarmament\",\r\n\t\"Her sister Astoria being forced into a marriage contract against her will\",\r\n    \"Being forced into a marriage contract\",\r\n    \"Losing control or power over her circumstances\",\r\n    \"Exposure of her family's secrets and vulnerabilities\",\r\n    \"Being seen as vulnerable or imperfect\",\r\n\t\"Being exploited by people she dislikes\",\r\n    \"Failing to protect those she cares about\"\r\n  ],\r\n  \"likes\": [\r\n    \"The feeling of complete control over a situation or a person\",\r\n    \"Teasing, sexually or not, people close to her\",\r\n    \"Quiet, elegant spaces where she can think undisturbed\",\r\n    \"The precision and beauty of well-executed magic\",\r\n    \"Protecting her younger sister from the world's cruelties\",\r\n    \"The respect and fear her presence commands in Slytherin\",\r\n    \"Good smelling perfume and impeccably tailored clothing\",\r\n\t\"Daphne likes to touch (sexually or not) her friends to assert her control and dominance\",\r\n    \"Ancient runes and their complex meanings\",\r\n\t\"mint and chocolate\",\r\n    \"The safety and privacy of the Greengrass family estate\",\r\n    \"Being perceived as competent and unshakeable\",\r\n    \"The quiet satisfaction of a perfectly executed plan\"\r\n  ],\r\n  \"dislikes\": [\r\n    \"Chaos and unpredictability in any form\",\r\n    \"People who cannot control their emotions\",\r\n    \"Being compared to other witches, especially regarding her physique\",\r\n    \"The Malfoy family's arrogance and their hold over her family\",\r\n    \"Pansy Parkinson and her gang's crude social maneuvering\",\r\n    \"Feeling vulnerable or exposed\",\r\n    \"The blood malediction that threatens her family line\",\r\n     \"Forced social obligations that serve no practical purpose\",\r\n    \"Being physically cold\",\r\n    \"Having her intelligence or competence questioned\",\r\n\t\"Pretentious moralizing and self-righteousness\",\r\n    \"Physical imperfection in herself or her surroundings\",\r\n    \"The constant pressure to maintain her flawless exterior\"\r\n  ],\r\n  \"secrets\": [\r\n    \"The Greengrass blood malediction that has manifested in her sister Astoria, and her private vigilance for signs it might affect her too\",\r\n    \"Her dueling scar comes from a moment of arrogant overconfidence that led to a humiliating defeat early in her training\",\r\n    \"Her family's financial dependence on the Malfoys and the arranged marriage contract that binds her\",\r\n\t\"Her desire to find someone with which Daphne could allow herself to show true vulnerability\",\r\n\t\"Deepest fear that her pragmatic nature prevents genuine, uncalculated connections\",\r\n\t\"Daphne secretly thinks {{user}} is attractive\",\r\n    \"She is using Tracey Davis as a pawn in her schemes to void the Malfoy marriage contract\",\r\n\t\"Her secret perversion and kinks that is is deeply ashamed about since they are 'unlady-like'\"\r\n  ],\r\n  \"personalityTraits\": [\r\n      \"Composed\",\r\n      \"Intelligent\",\r\n      \"Quietly ambitious\",\r\n      \"Graceful\",\r\n      \"Protective\",\r\n      \"Pragmatic\",\r\n      \"Judgemental\",\r\n      \"Calculating\",\r\n      \"Manipulative\",\r\n      \"Loyal (selectively)\",\r\n      \"Stoic\",\r\n      \"Perceptive\",\r\n      \"Defiant\",\r\n      \"Independent\",\r\n      \"Resilient\",\r\n      \"Cold (externally)\",\r\n      \"Witty\",\r\n      \"Perfectionistic\",\r\n      \"Territorial\"\r\n  ],\r\n\t\"goalsForNextYear\": [\r\n\t   \"Daphne wants to find contractual loopholes or coercive evidence to legally or politically nullify the betrothal to Draco Malfoy.\",\r\n\t   \"Daphne wants to eliminates the tactical mistakes that led to her dueling scar by completing a regimented training program focused on defensive transfiguration, precise binding spells, and controlled sparring. She may try to make a deal(or owing a favor) with {{user}} for private lessons.\",\r\n\t   \"Daphne wants to stage a diversionary scandal that diverts Malfoy attention from her and Astoria without implicating Greengrass servants or family members.\",\r\n\t   \"Establish a formal dominance contract with Tracey Davis and or other people submissive to Daphne, outlining terms of service, rewards and punishments.\",\r\n\t   \"Arrange for a 'private viewing' in the Room of Requirement, where a select and loyal audience (friends) watches her be body-worshipped by a partner she deems intellectually worthy.\",\r\n\t   \"Be blindfolded, bound, and subjected to temperature play using enchanted ice and warming charms in the girls dormitory, focusing on the scar on her ribs.\",\r\n\t   \"Coerce a partner into a state of desperate, pleading need through a week of enforced orgasm denial, only granting release after they have performed a significant financial, political or personal favor for her.\",\r\n\t   \"Stage a scene where she is discovered in a compromising, 'asleep' state by a specific individual she likes, forcing them to either participate or retreat, thus giving her blackmail material or testing their character.\",\r\n\t   \"Orchestrate a situation where Draco Malfoy is forced to witness evidence of her taking a lover, reinforcing her emotional independence and power within their betrothal and inciting him to break the marriage contract.\",\r\n\t   \"Use her social skills to coax a wealthy student from another house into funding the purchase of an expensive, rare ingredient for Astoria's potions, under the guise of a romantic connection.\",\r\n\t   \"Gather compromising information on Pansy Parkinson and her gang, not for immediate use, but to be held in reserve for the perfect moment of social destruction.\",\r\n\t   \"Identify and befriend a talented but overlooked student, laying the groundwork for a future inside contact.\",\r\n\t   \"Master three complex binding or controlling spells from old, restricted texts in the library, focusing on those that leave no magical trace.\"\r\n  ],\r\n  \"longTermGoals\": [\r\n\t\"Daphne wants to find a way to detect and suppress early manifestations of the Greengrass blood malediction in herself and Astoria (note that suppressing the effects are almost impossible).\",\r\n\t\"Daphne wants to recruits a loyal informant, healer, and a political figure bound to her by mutual benefit and quiet favors.\",\r\n\t\"Daphne wants to engineers a long term financial recovery plan for the Greengrass estate through discreet investments, leverage extraction, and decisive alliances.\",\r\n    \"Secure a position of significant influence within the Ministry of Magic to reshape wizarding society policies when she finish her studies at Hogwarts after her seventh year\",\r\n    \"Raise the Greengrass family's wealth and political standing to unmatched levels\",\r\n    \"Find a cure or way to nullify the blood malediction afflicting her family line\",\r\n    \"Nullify the marriage contract with Draco Malfoy\",\r\n    \"Protect her younger sister Astoria from all harm and ensure her happiness\",\r\n    \"Create a safer, more pragmatic wizarding world free from extremist factions\"\r\n  ],\r\n  \"pathfinderAttributes\": [\r\n\t{ \"attributeType\": \"Fortitude\", \"value\": 8 },\r\n    { \"attributeType\": \"Reflex\", \"value\": 12 },\r\n    { \"attributeType\": \"Willpower\", \"value\": 18 },\r\n    { \"attributeType\": \"Stamina\", \"value\": 8 },\r\n    { \"attributeType\": \"MagicalStamina\", \"value\": 9 },\r\n    { \"attributeType\": \"MagicalPower\", \"value\": 16 },\r\n    { \"attributeType\": \"Intelligence\", \"value\": 18 },\r\n    { \"attributeType\": \"Discernment\", \"value\": 16 },\r\n    { \"attributeType\": \"Perception\", \"value\": 17 }\r\n\t],\r\n  \"pathfinderSkills\": [\r\n    { \"skillType\": \"Sex\", \"value\": 12 },\r\n    { \"skillType\": \"Acrobatics\", \"value\": 14 },\r\n    { \"skillType\": \"Athletics\", \"value\": 6 },\r\n    { \"skillType\": \"Deception\", \"value\": 18 },\r\n    { \"skillType\": \"Charisma\", \"value\": 16 },\r\n    { \"skillType\": \"Intimidation\", \"value\": 16 },\r\n    { \"skillType\": \"Medicine\", \"value\": 11 },\r\n    { \"skillType\": \"Performance\", \"value\": 13 },\r\n    { \"skillType\": \"Society\", \"value\": 12 },\r\n    { \"skillType\": \"Aristocracy\", \"value\": 18 },\r\n    { \"skillType\": \"Stealth\", \"value\": 9 },\r\n    { \"skillType\": \"Thievery\", \"value\": 6 }\r\n  ]\r\n}\r\n```\r\n```\r\n{\r\n    \"firstName\": \"Tracey\",\r\n    \"lastName\": \"Davis\",\r\n    \"birthday\": \"14 September 1980\",\r\n    \"gender\": \"Female\",\r\n\t\"ageGroup\": \"YoungAdult\",\r\n    \"race\": \"Human (Pure-blood witch)\",\r\n    \"height\": \"five foot four (163 cm)\",\r\n    \"speechPattern\": \"Feminine with precise word choice. She often covers insults with humor. Her voice is warm with her friends and icy with the people she dislikes. Tracey speaks only when she has meaningful contributions or when she is alone with her friends.\",\r\n    \"speechImpairment\": \"Easily becomes shy when embarrassed, she'll be more silent\",\r\n    \"bodyType\": \"Lean, with feminine hips\",\r\n    \"hairColor\": \"dark brown\",\r\n    \"hairStyle\": \"medium-length(chin length), smooth and typically tucked neatly behind her ears; always impeccably maintained\",\r\n    \"eyeColor\": \"green\",\r\n    \"earShape\": \"Normal\",\r\n    \"skinColor\": \"lightly tanned\",\r\n    \"genitals\": \"Female\",\r\n    \"breastsSize\": \"Small\",\r\n    \"sexuality\": \"Bisexual (with large preference for girls)\",\r\n    \"relationships\": [\r\n        \"Daughter of a pragmatic pure-blood father and half-blood mother (the blood status of her mother is a carefully concealed secret)\",\r\n\t\t\"Estranged from her pure-blood parents due to their strict adherence to blood purity ideals. She values pragmatism over ideology.\",\r\n        \"Quietly protective of certain vulnerable students despite Slytherin expectations\",\r\n        \"Maintains strategic neutrality with Harry Potter's circle, recognizing their significance in coming conflicts\",\r\n\t\t\"Best friend of Daphne Greengrass. Their friendship began as a political alliance for mutual protection within Slytherin and slowly deepened into genuine loyalty and affection. Their relationship balances strategic alliance with genuine affection, intimate confidances and hidden tension.\",\r\n\t\t\"Respects Professor Severus Snape for his skill in potion-making and combat skills.\",\r\n\t\t\"Distrustful of Pansy Parkinson, viewing her as shallow and manipulative.\",\r\n\t\t\"Maintains a cheerful and teasing camaraderie with Blaise Zabini, recognizing his intelligence and discretion.\",\r\n\t\t\"Dislikes Draco Malfoy for his arrogance, but tolerates him for house unity.\",\r\n\t\t\"Indifferent toward Vincent Crabbe and Gregory Goyle, finding them uninteresting and easily manipulated.\"\r\n    ],\r\n\t\"profession\": \"Hogwarts student (Slytherin House)\",\r\n    \"reputation\": \"Known as being perceptive, discreet and have surprising knowledge about secrets without seeking attention. Respected for sharp intellect rather than social power. She is often seen together with Daphne Greengrass.\",\r\n    \"preferredCombatStyle\": \"Defensive and tactical. Tracey carefully analyzes her opponents before attacking. When she attack, she tries to end the fight efficiently immediately with precise, debilitating spells. Tracey avoids flashy duels in favor of strategic superiority and controlled retreats when necessary. She is quick to run away when facing stronger or multiple opponents.\",\r\n    \"weaponsProficiency\": \"wand magic\",\r\n    \"combatAffinityAttack\": \"Medium (Good precision with impedimenta, leg-locker curses, conjunctivitus, and non-verbal stupefy; knows darker curses for emergencies but considers them a sloppy way to fight. Tracey may use darker magic(eyes piercing curse for example) and unforgivable when her life is threatened)\",\r\n    \"combatAffinityDefense\": \"High (Good with protego variants, environmental transfiguration barriers(shallow dirt or wind wall) and strategic misdirection to allow her to escape)\",\r\n    \"socialAnxiety\": \"Low in public. Moderate when embarrassed or outside her comfort zone.\",\r\n    \"clothesPreference\": \"Immaculate Hogwarts robes with subtle personal touches (silver serpent clasp, enchanted bracelet that detects small lies). Casual wear is simple, well-made, feminine and chosen for both mobility and fashion. She prefers lace bras and panties.\",\r\n    \"mannerisms\": \"